const body = $json.body ?? $json;
if (!process.env.LS_N8N_CLIENT_SECRET) { throw new Error('LS_N8N_CLIENT_SECRET is not configured'); }
if (body.clientSecret !== process.env.LS_N8N_CLIENT_SECRET) { throw new Error('Invalid client secret'); }
return [{ json: { ...body, acumaticaBaseUrl: process.env.ACUMATICA_BASE_URL, endpointBase: (process.env.ACUMATICA_BASE_URL || '').replace(/\/$/, '') + '/entity/LSOpportunityNotes/25.200.001' } }];

const request = $node['Validate Secret and Normalize Request'].json;
const opportunity = $node['GET Opportunity Context'].json;
const meetingNotes = $node['GET Related Meeting Notes and Transcripts'].json;
return [{ json: { request, opportunity, meetingNotes } }];

const content = $json.content || [];
const answer = Array.isArray(content) ? content.map(part => part.text || '').join('\n').trim() : JSON.stringify($json);
return [{ json: { answer } }];
